#[test]
fn test_bootstrap_convergence() {
    // Test that bootstrap estimates converge with sufficient samples
    use resample::{bootstrap, BootstrapConfig, BootstrapStatistic};

    #[derive(Clone, Copy)]
    struct SimpleStatistic;

    impl BootstrapStatistic for SimpleStatistic {
        fn compute(&self, _x: ndarray::ArrayView2<f64>, y: ndarray::ArrayView1<f64>) -> Array1<f64> {
            Array1::from(vec![y.mean().unwrap_or(0.0)])
        }

        fn n_stats(&self) -> usize {
            1
        }
    }

    let n_obs = 50;
    let x_data = Array2::ones((n_obs, 2));
    let y_data = Array1::from((0..n_obs).map(|i| i as f64).collect::<Vec<_>>());
    let true_mean = y_data.mean().unwrap();

    let stat = SimpleStatistic;

    // Test with increasing sample sizes
    for &n_samples in &[100, 500, 1000] {
        let config = BootstrapConfig {
            n_samples,
            seed: Some(42),
            parallel: true,
        };

        let result = bootstrap(x_data.view(), y_data.view(), stat, Some(config)).unwrap();

        let bootstrap_mean = result.estimates[0];
        let error = (bootstrap_mean - true_mean).abs();

        // Error should decrease with more samples
        assert!(error < 5.0, "Bootstrap estimate should be close to true mean");

        println!("Bootstrap with {} samples: estimate = {:.3}, true = {:.3}, error = {:.3}", 
                 n_samples, bootstrap_mean, true_mean, error);
    }
}

